class Solution:
    def slowestKey(self, releaseTimes, keysPressed):
        best_key = keysPressed[0]
        best_dur = releaseTimes[0]
        prev = releaseTimes[0]
        for i in range(1, len(releaseTimes)):
            dur = releaseTimes[i] - prev
            key = keysPressed[i]
            if dur > best_dur or (dur == best_dur and key > best_key):
                best_dur = dur
                best_key = key
            prev = releaseTimes[i]
        return best_key

